#define CI const int
#define NP namespace
using NP std;
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
        a=a*a;
		b>>=1;
	}
	return ans;
}
CI MAXN = 5e5 + 5;
int n, m, a[MAXN],d[MAXN],cnt,tot;
void fix(int x, int y)
{
    while(x<=MAXN) a[x]+=y,x+=(x&-x);
}
int get_sum(int x)
{
    int t=0;
    while(x) t+=a[x],x-=(x&-x);
    return t;
}
signed main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        char c;
        cin>>c;
        if(c=='A')
        {
            int l,r;
            cin>>l>>r;
            cnt=0;
            wh(true)
            {
                int Left=-1,Right=r+1;
                wh(Left+1<Right)
                {
                    int mid=(Left+Right)>>1;
                    if(get_sum(mid)>=get_sum(r))
                    {
                        Right=mid;
                    }
                    else
                    {
                        Left=mid;
                    }
                }
                if(d[Right]>=l)
                {  
                    fix(Right,-1);
                    cnt++;
                    tot--;
                }
                else break;
            }
            cout<<cnt<<'\n';
            fix(l,1);
            d[l]=r;  
            ++tot;
        }
        else
        {
           cout<<tot<<'\n';
        }
    }
	return false;
}
